#!/usr/bin/env python3\n\"\"\"\nSupabase Connection Test Script\nRun this to verify your Supabase integration is working\n\"\"\"\n\nimport os\nimport sys\nfrom dotenv import load_dotenv\n\n# Load environment variables\nload_dotenv()\n\n# Add parent directory to path\nsys.path.append(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))\n\ntry:\n    from supabase_config import SupabaseManager\n    print(\"✅ Supabase config imported successfully\")\nexcept ImportError as e:\n    print(f\"❌ Failed to import Supabase config: {e}\")\n    sys.exit(1)\n\ndef test_supabase_connection():\n    \"\"\"Test Supabase connection and basic operations\"\"\"\n    \n    print(\"\\n🔍 Testing Supabase Connection...\")\n    \n    # Check environment variables\n    url = os.getenv('SUPABASE_URL')\n    key = os.getenv('SUPABASE_ANON_KEY')\n    \n    if not url or not key:\n        print(\"❌ Missing environment variables:\")\n        print(f\"   SUPABASE_URL: {'✅' if url else '❌ Missing'}\")\n        print(f\"   SUPABASE_ANON_KEY: {'✅' if key else '❌ Missing'}\")\n        print(\"\\n💡 Make sure to:\")\n        print(\"   1. Copy .env.example to .env\")\n        print(\"   2. Add your Supabase credentials to .env\")\n        return False\n    \n    print(f\"✅ Environment variables configured\")\n    print(f\"   URL: {url[:30]}...\")\n    print(f\"   Key: {key[:20]}...\")\n    \n    # Test connection\n    try:\n        manager = SupabaseManager()\n        print(\"✅ Supabase client created successfully\")\n    except Exception as e:\n        print(f\"❌ Failed to create Supabase client: {e}\")\n        return False\n    \n    # Test logging a prediction\n    print(\"\\n📝 Testing prediction logging...\")\n    test_input = {\n        \"crosswalk_wait_sec\": 35.0,\n        \"litter_density_per_100m2\": 5.0,\n        \"midnight_noise_db\": 58.0,\n        \"atm_queue_length\": 2.0,\n        \"vacant_storefronts_pct\": 10.0,\n        \"dog_walk_freq_per_hr\": 1.0,\n        \"graffiti_turnover_days\": 10.0\n    }\n    \n    model_info = {\n        \"model_name\": \"Test Model\",\n        \"accuracy\": 0.85\n    }\n    \n    result = manager.log_prediction(test_input, \"Med\", model_info)\n    if result:\n        print(\"✅ Test prediction logged successfully\")\n        print(f\"   Record ID: {result[0]['id'] if result else 'N/A'}\")\n    else:\n        print(\"❌ Failed to log test prediction\")\n        return False\n    \n    # Test getting statistics\n    print(\"\\n📊 Testing statistics retrieval...\")\n    stats = manager.get_prediction_stats()\n    if stats:\n        print(\"✅ Statistics retrieved successfully\")\n        print(f\"   Total predictions: {stats['total_predictions']}\")\n        print(f\"   Low stress: {stats['low_stress']}\")\n        print(f\"   Med stress: {stats['med_stress']}\")\n        print(f\"   High stress: {stats['high_stress']}\")\n    else:\n        print(\"❌ Failed to retrieve statistics\")\n        return False\n    \n    # Test getting recent predictions\n    print(\"\\n📋 Testing recent predictions retrieval...\")\n    recent = manager.get_recent_predictions(5)\n    if recent is not None:\n        print(f\"✅ Retrieved {len(recent)} recent predictions\")\n        if recent:\n            latest = recent[0]\n            print(f\"   Latest prediction: {latest['prediction']} at {latest['created_at']}\")\n    else:\n        print(\"❌ Failed to retrieve recent predictions\")\n        return False\n    \n    print(\"\\n🎉 All Supabase tests passed!\")\n    print(\"\\n💡 Next steps:\")\n    print(\"   1. Start your Flask app: cd backend && python app.py\")\n    print(\"   2. Test the API endpoints\")\n    print(\"   3. Check your Supabase dashboard for logged data\")\n    \n    return True\n\nif __name__ == \"__main__\":\n    print(\"🏙️ Urban Stress ML - Supabase Connection Test\")\n    print(\"=\" * 50)\n    \n    success = test_supabase_connection()\n    \n    if success:\n        print(\"\\n✅ Supabase integration is working correctly!\")\n        sys.exit(0)\n    else:\n        print(\"\\n❌ Supabase integration test failed.\")\n        print(\"\\n📖 Check SUPABASE_SETUP.md for detailed setup instructions.\")\n        sys.exit(1)